// Process faith script for audio generation
const script = $input.first().json.script;

// Clean script for text-to-speech
let cleanScript = script
  .replace(/\[PAUSE\]/g, '... ')
  .replace(/\[EMPHASIS\]/g, '')
  .replace(/\[VISUAL:.*?\]/g, '')
  .replace(/\[PRAYER\]/g, '')
  .replace(/\[MERCHANDISE\]/g, '')
  .replace(/\[.*?\]/g, '')
  .replace(/\s+/g, ' ')
  .trim();

// Extract scripture references
const scriptureRefs = [];
const scriptureMatches = script.match(/\b\d*\s*[A-Za-z]+\s+\d+:\d+(-\d+)?\b/g);
if (scriptureMatches) {
  scriptureRefs.push(...scriptureMatches);
}

// Extract visual cues for graphics
const visualCues = [];
const visualMatches = script.match(/\[VISUAL:(.*?)\]/g);
if (visualMatches) {
  visualMatches.forEach(match => {
    const cue = match.replace(/\[VISUAL:|\]/g, '').trim();
    visualCues.push(cue);
  });
}

// Extract prayer segments
const prayerSegments = [];
const prayerMatches = script.match(/\[PRAYER\](.*?)(?=\[|$)/gs);
if (prayerMatches) {
  prayerMatches.forEach(match => {
    const prayer = match.replace(/\[PRAYER\]/g, '').trim();
    if (prayer) prayerSegments.push(prayer);
  });
}

// Generate keywords for faith-based imagery
const faithKeywords = [
  'cross', 'bible', 'prayer', 'faith', 'hope', 'peace',
  'worship', 'church', 'christian', 'spiritual', 'blessed',
  'grace', 'salvation', 'jesus', 'god', 'holy'
];

return {
  script_clean: cleanScript,
  script_original: script,
  scripture_references: scriptureRefs,
  visual_cues: visualCues,
  prayer_segments: prayerSegments,
  visual_keywords: faithKeywords.join(' '),
  word_count: cleanScript.split(' ').length
};
